$sec = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force; $cred = New-Object System.Management.Automation.PSCredential('.\usr1cv8', $sec); Invoke-Command -ComputerName 26.168.226.201 -Credential $cred -Authentication Negotiate -ScriptBlock {
  Write-Output '=== QUERY LICENSE LIST via TCP 756 ==='
  function Send-LicReq($port, $body) {
    try {
      $client = New-Object System.Net.Sockets.TcpClient('127.0.0.1', $port)
      $stream = $client.GetStream()
      $data = [System.Text.Encoding]::UTF8.GetBytes($body)
      $stream.Write($data, 0, $data.Length)
      Start-Sleep -Milliseconds 800
      $buf = New-Object byte[] 65536
      $read = $stream.Read($buf, 0, $buf.Length)
      $client.Close()
      return [System.Text.Encoding]::UTF8.GetString($buf, 0, $read)
    } catch { return $_.Exception.Message }
  }

  # try common JSON-RPC style payloads used by ATOL LM
  $payloads = @(
    '{"method":"getLicenseList","parameters":{}}',
    '{"method":"getServiceInfo","parameters":{}}',
    '{"method":"getLicenseInfo","parameters":{"number":"AW1W2-D19B7-6TBPA-9MC6Q"}}'
  )
  foreach ($p in $payloads) {
    Write-Output ("--- 756: $p ---")
    Send-LicReq 756 $p
    Write-Output ''
    Write-Output ("--- 755: $p ---")
    Send-LicReq 755 $p
    Write-Output ''
  }

  Write-Output '=== CONTEXT AROUND NOT ACTIVATED ==='
  Select-String -Path 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvcEx.log' -Pattern 'AW1W2|не актив|активир|Licenses updated|error' -Context 2,2 |
    Select-Object -Last 30 |
    ForEach-Object {
      if ($_.Context.PreContext) { $_.Context.PreContext | ForEach-Object { "  $_" } }
      ">$($_.Line)"
      if ($_.Context.PostContext) { $_.Context.PostContext | ForEach-Object { "  $_" } }
      '----'
    }

  Write-Output '=== FRONTOL CURRENT STATUS ==='
  Get-Service frontol-mu,AtolLicSvc | Format-Table Name,Status -AutoSize | Out-String
  Get-Process frontol-mu,AtolLicSvcStart -ErrorAction SilentlyContinue | Format-Table Id,ProcessName,StartTime -AutoSize | Out-String

